module SR_latch (
    input wire SR_S,
    input wire R,
    output reg Q,
    output reg Qn
);
    always @ (SR_S or R) begin
        if (SR_S && !R) begin
            Q <= 1'b1;
            Qn <= 1'b0;
        end else if (!SR_S && R) begin
            Q <= 1'b0;
            Qn <= 1'b1;
        end
        // If both SR_S and R are low, keep the previous state
    end
endmodule
